import{_ as t,o as a,c as r,ad as i}from"./chunks/framework.DdcUsuRQ.js";const m=JSON.parse('{"title":"RGB","description":"How iridis stores sRGB as floating-point unit-interval triples, the piecewise gamma transfer function, and when linear vs gamma-corrected values are required","frontmatter":{"title":"RGB","description":"How iridis stores sRGB as floating-point unit-interval triples, the piecewise gamma transfer function, and when linear vs gamma-corrected values are required","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/rgb"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/rgb"}],["meta",{"property":"og:title","content":"RGB: iridis"}],["meta",{"property":"og:description","content":"How iridis stores sRGB as floating-point unit-interval triples, the piecewise gamma transfer function, and when linear vs gamma-corrected values are required"}],["meta",{"name":"twitter:title","content":"RGB: iridis"}],["meta",{"name":"twitter:description","content":"How iridis stores sRGB as floating-point unit-interval triples, the piecewise gamma transfer function, and when linear vs gamma-corrected values are required"}],["meta",{"name":"description","content":"How iridis stores sRGB as floating-point unit-interval triples, the piecewise gamma transfer function, and when linear vs gamma-corrected values are required"}],["meta",{"property":"article:modified_time","content":"2026-05-17T03:59:59.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"RGB\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/rgb\\"}]}"]]},"headers":[],"relativePath":"reference/rgb.md","filePath":"reference/rgb.md","lastUpdated":1778990399000}'),o={name:"reference/rgb.md"};function s(c,e,n,d,l,p){return a(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="rgb" tabindex="-1">RGB <a class="header-anchor" href="#rgb" aria-label="Permalink to &quot;RGB&quot;">​</a></h1><p>RGB describes a color as a triple of red, green, and blue intensities. <span class="iridis-brand">iridis</span> stores RGB in floating-point form on the unit interval <code>[0, 1]</code>, in the sRGB color space.</p><h2 id="srgb" tabindex="-1">sRGB <a class="header-anchor" href="#srgb" aria-label="Permalink to &quot;sRGB&quot;">​</a></h2><p>sRGB is the IEC 61966-2-1 standard color space used by the open web, most consumer displays, and every common image format. It defines:</p><ul><li>A set of primaries (chromaticities for red, green, blue).</li><li>A reference white (D65).</li><li>A non-linear transfer function (gamma encoding) that compresses linear light for storage.</li></ul><p>When a hex string <code>#7c3aed</code> is read into <span class="iridis-brand">iridis</span>, the bytes are interpreted as gamma-encoded sRGB. Each byte is divided by 255 to produce a value in <code>[0, 1]</code>. The result is a gamma-corrected sRGB triple, not linear light.</p><h2 id="gamma-corrected-vs-linear" tabindex="-1">Gamma-corrected vs linear <a class="header-anchor" href="#gamma-corrected-vs-linear" aria-label="Permalink to &quot;Gamma-corrected vs linear&quot;">​</a></h2><p>The sRGB transfer function is piecewise. The decode (gamma-corrected → linear) is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>v_linear = v / 12.92                          if v ≤ 0.04045</span></span>
<span class="line"><span>         = ((v + 0.055) / 1.055) ^ 2.4         otherwise</span></span></code></pre></div><p>The encode (linear → gamma-corrected) is the inverse:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>v = 12.92 · v_linear                          if v_linear ≤ 0.0031308</span></span>
<span class="line"><span>  = 1.055 · v_linear ^ (1/2.4) − 0.055        otherwise</span></span></code></pre></div><p>Linear sRGB is required whenever physical light addition matters: relative luminance for WCAG, CIE XYZ conversion en route to OKLCH, and any blending model that claims to be perceptually correct.</p><p>Gamma-corrected sRGB is what gets written to a hex string, sent to a <code>&lt;canvas&gt;</code>, or set as a CSS color.</p><h2 id="conversion-to-oklch" tabindex="-1">Conversion to OKLCH <a class="header-anchor" href="#conversion-to-oklch" aria-label="Permalink to &quot;Conversion to OKLCH&quot;">​</a></h2><p>The path is sRGB → linear sRGB → CIE XYZ-like cone responses → cube-root non-linearity → Oklab → polar form (OKLCH). The matrices are encoded in <code>ColorRecordFactory</code> (<code>packages/core/src/math/ColorRecordFactory.ts</code>); see <a href="./oklch">OKLCH</a> for the full pipeline.</p><h2 id="math-primitives" tabindex="-1">Math primitives <a class="header-anchor" href="#math-primitives" aria-label="Permalink to &quot;Math primitives&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Primitive</th><th>File</th><th>Behaviour</th></tr></thead><tbody><tr><td><code>srgbToLinear</code></td><td><code>packages/core/src/math/SrgbToLinear.ts</code></td><td>gamma-decodes a triple of sRGB channels into linear sRGB</td></tr><tr><td><code>linearToSrgb</code></td><td><code>packages/core/src/math/LinearToSrgb.ts</code></td><td>gamma-encodes a triple of linear sRGB channels back to sRGB</td></tr><tr><td><code>rgbToOklch</code></td><td><code>packages/core/src/math/RgbToOklch.ts</code></td><td>builds a <code>ColorRecord</code> from three sRGB channels via <code>ColorRecordFactory.fromRgb</code></td></tr><tr><td><code>oklchToRgb</code></td><td><code>packages/core/src/math/OklchToRgb.ts</code></td><td>builds a <code>ColorRecord</code> from L, C, h via <code>ColorRecordFactory.fromOklch</code></td></tr><tr><td><code>oklchToRgbRaw</code></td><td><code>packages/core/src/math/OklchToRgbRaw.ts</code></td><td>converts L, C, h to an sRGB triple without allocating a <code>ColorRecord</code> (hot-loop primitive used by <code>EnsureContrast</code> and the factory)</td></tr><tr><td><code>oklchToDisplayP3</code></td><td><code>packages/core/src/math/OklchToDisplayP3.ts</code></td><td>converts L, C, h to a Display-P3 RGB triple; unclamped so out-of-sRGB inputs survive</td></tr><tr><td><code>gamutMapSrgb</code></td><td><code>packages/core/src/math/GamutMapSrgb.ts</code></td><td>CSS Color 4 §13.2.2 chroma-reduction gamut mapping; reports <code>inGamut</code> flag</td></tr><tr><td><code>mixSrgb</code></td><td><code>packages/core/src/math/MixSrgb.ts</code></td><td>linear interpolation in gamma-corrected sRGB (fast, perceptually crude)</td></tr></tbody></table><p><code>luminance</code> (<code>packages/core/src/math/Luminance.ts</code>) and the WCAG / APCA contrast primitives all depend on the sRGB → linear decode internally.</p><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li><code>intake:rgb</code> (<code>packages/core/src/tasks/intake/IntakeRgb.ts</code>) accepts <code>{r, g, b}</code> objects from <code>input.colors</code>.</li><li>Every <code>ColorRecord</code> carries an <code>rgb</code> field alongside <code>oklch</code> and <code>hex</code>. Consumers that need to output a CSS color or a numeric byte triple read from this field directly.</li><li>The contrast plugin reads <code>rgb</code> to compute relative luminance for both WCAG and APCA without reaching back through OKLCH.</li></ul>`,20)])])}const g=t(o,[["render",s]]);export{m as __pageData,g as default};
